"use strict";(self.webpackChunkblog=self.webpackChunkblog||[]).push([[6437],{8362:(n,s,a)=>{a.r(s),a.d(s,{data:()=>p});const p={key:"v-2970661c",path:"/posts/%E7%8E%AF%E5%A2%83%E5%8F%98%E9%87%8F.html",title:"环境变量及在vue中的配置",lang:"en-US",frontmatter:{layout:"Post",title:"环境变量及在vue中的配置",date:"2021-12-28T00:00:00.000Z",headerImage:"/img/in-post/2021-12-9/01.jpg",catalog:!0,tags:["环境变量"]},excerpt:"",headers:[{level:2,title:"1，简介",slug:"_1-简介",children:[]},{level:2,title:"2，使用",slug:"_2-使用",children:[{level:3,title:"[1]创建.env文件",slug:"_1-创建-env文件",children:[]},{level:3,title:"[2]获取环境变量",slug:"_2-获取环境变量",children:[]},{level:3,title:"[2]配置文件说明",slug:"_2-配置文件说明",children:[{level:4,title:"环境变量的权重",slug:"环境变量的权重",children:[]}]},{level:3,title:"[3]配置文件中的变量名问题",slug:"_3-配置文件中的变量名问题",children:[{level:4,title:"vuecli",slug:"vuecli",children:[]},{level:4,title:"vite",slug:"vite",children:[]}]}]},{level:2,title:"3，应用举例",slug:"_3-应用举例",children:[{level:3,title:"[1]环境配置封装",slug:"_1-环境配置封装",children:[]},{level:3,title:"[2]mock数据",slug:"_2-mock数据",children:[]}]}],git:{updatedTime:165448575e4},readingTime:{minutes:6,words:1452},filePathRelative:"posts/环境变量.md"}},8979:(n,s,a)=>{a.r(s),a.d(s,{default:()=>t});const p=(0,a(6252).uE)('<h2 id="_1-简介" tabindex="-1"><a class="header-anchor" href="#_1-简介" aria-hidden="true">#</a> 1，简介</h2><p>一个项目可能会有开发版本、上线版本、测试版本等等多个版本，不同的环境会有不同请求api接口，就需更改一些基本配置，基本路径，服务器代理这种都要更改一遍，这时候就显得很麻烦，所以这里就使用了环境变量。若手动切换接口地址是相当繁琐且易出错的。于是环境变量配置的需求就应运而生，我们只需做简单的配置，把环境状态切换的工作交给代码。</p><ul><li>开发环境（开发阶段，本地开发版本，一般会使用一些调试工具或额外的辅助功能）</li><li>测试环境（测试阶段，上线前版本，除了一些 bug 的修复，基本不会和上线版本有很大差别）</li><li>生产环境（上线阶段，正式对外发布的版本，一般会进行优化，关掉错误报告）</li></ul><h2 id="_2-使用" tabindex="-1"><a class="header-anchor" href="#_2-使用" aria-hidden="true">#</a> 2，使用</h2><h3 id="_1-创建-env文件" tabindex="-1"><a class="header-anchor" href="#_1-创建-env文件" aria-hidden="true">#</a> [1]创建.env文件</h3><ul><li><p>直接在根目录下创建<code>.env</code>后缀的文件</p></li><li><p>.<code>env</code> ——全局的，没有设置其他环境变量时，会加载这个文件里的内容，比如所有版本都使用的是同一个接口地址时,就可以写在这一个文件里面就行</p></li><li><p><code>.env.development</code> ——开发环境下的配置文件，会覆盖.env这个文件里定义的环境变量（比如执行npm run dev命令，会自动加载.<code>env.development</code>文件）</p></li><li><p><code>.env.production</code> ——生产环境下的配置文件，会覆盖 .env这个文件里定义的环境变量</p></li></ul><div class="language-json ext-json"><pre class="language-json"><code>#例如在配置文件中\n<span class="token property">&quot;scripts&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token property">&quot;dev&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vite --mode dev&quot;</span><span class="token punctuation">,</span> <span class="token comment">//-开发环境时选择.env.dev作为环境配置文件</span>\n    <span class="token property">&quot;build&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vite build&quot;</span><span class="token punctuation">,</span>\n    <span class="token property">&quot;serve&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vite preview&quot;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n</code></pre></div><h3 id="_2-获取环境变量" tabindex="-1"><a class="header-anchor" href="#_2-获取环境变量" aria-hidden="true">#</a> [2]获取环境变量</h3><p>之前使用vuecli构建的项目可以通过<code>process.env</code>来获取环境变量，但是在vite中不允许了</p><div class="language-javascript ext-js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;环境变量=&gt;&quot;</span><span class="token punctuation">,</span>process<span class="token punctuation">.</span>env<span class="token punctuation">)</span> <span class="token comment">//error</span>\n</code></pre></div><p>vite中需要使用import.meta.env来获取env对象了</p><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token comment">//main.js</span>\n<span class="token keyword">import</span> <span class="token punctuation">{</span> createApp <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n<span class="token keyword">import</span> App <span class="token keyword">from</span> <span class="token string">&#39;./App.vue&#39;</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;环境变量=&gt;&quot;</span><span class="token punctuation">,</span> <span class="token keyword">import</span><span class="token punctuation">.</span>meta<span class="token punctuation">.</span>env<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token function">createApp</span><span class="token punctuation">(</span>App<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">mount</span><span class="token punctuation">(</span><span class="token string">&#39;#app&#39;</span><span class="token punctuation">)</span>\n</code></pre></div><p><img src="环境变量.assets/202204141927366.png" alt="image-20211124221154916"></p><p>根据环境变量<a href="https://cn.vitejs.dev/guide/env-and-mode.html#env-variables" target="_blank" rel="noopener noreferrer">官方文档</a></p><p>Vite 在一个特殊的 <strong><code>import.meta.env</code></strong> 对象上暴露环境变量。这里有一些在所有情况下都可以使用的内建变量：</p><ul><li><strong><code>import.meta.env.MODE</code></strong>: {string} 应用运行的<a href="https://cn.vitejs.dev/guide/env-and-mode.html#modes" target="_blank" rel="noopener noreferrer">模式</a>。</li><li><strong><code>import.meta.env.BASE_URL</code></strong>: {string} 部署应用时的基本URL。他由<a href="https://cn.vitejs.dev/config/#base" target="_blank" rel="noopener noreferrer"><code>base</code> 配置项</a>决定。</li><li><strong><code>import.meta.env.PROD</code></strong>: {boolean} 应用是否运行在生产环境。</li><li><strong><code>import.meta.env.DEV</code></strong>: {boolean} 应用是否运行在开发环境 (永远与 <code>import.meta.env.PROD</code>相反)。</li></ul><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token comment">//例如在项目根目录下创建一个.env.dev文件</span>\n<span class="token constant">MODE_DEV</span><span class="token operator">=</span>development <span class="token comment">//定义env对象的MOOD的名称</span>\nVITE_Name<span class="token operator">=</span>jack\n<span class="token comment">//package.json</span>\n<span class="token string-property property">&quot;dev&quot;</span><span class="token operator">:</span> <span class="token string">&quot;vite --mode dev&quot;</span><span class="token punctuation">,</span>\n</code></pre></div><p><img src="环境变量.assets/202204141927927.png" alt="image-20211124222100762"></p><p><a href="%22.env.%5Bname%5D%22%E6%98%AF%E5%8F%AF%E4%BB%A5%E8%87%AA%E5%AE%9A%E4%B9%89%E7%9A%84%EF%BC%8C%E5%89%8D%E6%8F%90%E6%98%AF%E5%BE%97%E5%9C%A8package.json%E9%87%8C%E9%9D%A2%E5%81%9A%E5%AF%B9%E5%BA%94%E7%9A%84%E5%90%8D%E7%A7%B0%E4%BF%AE%E6%94%B9,%E5%8F%AA%E6%98%AF%E6%B2%A1%E6%9C%89%E4%BF%AE%E6%94%B9%E7%9A%84%E8%AF%9D%E4%BC%9A%E9%BB%98%E8%AE%A4%E9%BB%98%E8%AE%A4">^注</a>: 只有以 <code>VITE_</code> 为前缀的变量才会暴露给经过vite处理的代码。例如：才能通过<code>import.meta.env.VITE_Name</code>相应变量的值。（vite环境下为VITE，vuecli环境下为VUE)</p><h3 id="_2-配置文件说明" tabindex="-1"><a class="header-anchor" href="#_2-配置文件说明" aria-hidden="true">#</a> [2]配置文件说明</h3><h4 id="环境变量的权重" tabindex="-1"><a class="header-anchor" href="#环境变量的权重" aria-hidden="true">#</a> 环境变量的权重</h4><div class="language-text ext-text"><pre class="language-text"><code>.env.[mode].local &gt; .env.[mode] &gt; .env.local &gt; .env \n</code></pre></div><h3 id="_3-配置文件中的变量名问题" tabindex="-1"><a class="header-anchor" href="#_3-配置文件中的变量名问题" aria-hidden="true">#</a> [3]配置文件中的变量名问题</h3><p>我们在 Vue 的前端代码中打印出的 <code>process.env</code> 与 <code>vue.config.js</code>配置文件中输出的可能是不一样的。</p><h4 id="vuecli" tabindex="-1"><a class="header-anchor" href="#vuecli" aria-hidden="true">#</a> vuecli</h4><ul><li>推荐环境配置文件中以 <code>VUE_APP_</code> 开头（<code>NODE_ENV</code> 和 <code>BASE_URL</code> 这两个特殊变量除外）</li><li>这样才能在项目(客户端）代码中通过<code>process.env</code>获取到该变量（在配置vue.config.js（服务端）文件中取到）</li><li>其原理为webpack DefinePlugin 内置插件的相关内容，将process.env注入到客户端代码中。</li><li>但是经过CLI封装后仅支持注入环境配置文件中以<code>VUE_APP_</code> 开头的变量，而 <code>NODE_ENV</code> 和 <code>BASE_URL</code> 这两个特殊变量除外。</li></ul><p><img src="环境变量.assets/202204141927536.png" alt="image-20211126233212993"></p><h4 id="vite" tabindex="-1"><a class="header-anchor" href="#vite" aria-hidden="true">#</a> vite</h4><ul><li>为了防止意外地将一些环境变量泄漏到客户端，在vite中同理：要以 <code>VITE_</code> 为前缀的变量才会暴露前端代码（客户端）</li><li>不同于vuecli可以在vue.config.js中直接通过<code>process.env</code>直接获取环境变量，在vite中是不可以直接使用<code>import.meta.env</code>来获取的</li><li>这里有一个模式的概念，需要根据项目的一些需求来进行配置获取，详见官方文档吧</li></ul><h2 id="_3-应用举例" tabindex="-1"><a class="header-anchor" href="#_3-应用举例" aria-hidden="true">#</a> 3，应用举例</h2><h3 id="_1-环境配置封装" tabindex="-1"><a class="header-anchor" href="#_1-环境配置封装" aria-hidden="true">#</a> [1]环境配置封装</h3><div class="language-javascript ext-js"><pre class="language-javascript"><code>#src<span class="token operator">/</span>config<span class="token operator">/</span>index<span class="token punctuation">.</span>js\n<span class="token keyword">const</span>  env <span class="token operator">=</span> <span class="token keyword">import</span><span class="token punctuation">.</span>meta<span class="token punctuation">.</span>env<span class="token punctuation">.</span><span class="token constant">MODE</span> <span class="token operator">||</span> <span class="token string">&#39;prod&#39;</span><span class="token punctuation">;</span>\n<span class="token keyword">const</span> EnvConfig <span class="token operator">=</span> <span class="token punctuation">{</span>\n    <span class="token comment">//开发环境</span>\n    <span class="token literal-property property">dev</span><span class="token operator">:</span><span class="token punctuation">{</span>\n        <span class="token literal-property property">baseApi</span><span class="token operator">:</span><span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>\n        <span class="token literal-property property">mockApi</span><span class="token operator">:</span><span class="token string">&#39;&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token comment">//测试环境</span>\n    <span class="token literal-property property">test</span><span class="token operator">:</span><span class="token punctuation">{</span>\n        <span class="token literal-property property">baseApi</span><span class="token operator">:</span><span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>\n        <span class="token literal-property property">mockApi</span><span class="token operator">:</span><span class="token string">&#39;&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token comment">//生产环境</span>\n    <span class="token literal-property property">prod</span><span class="token operator">:</span><span class="token punctuation">{</span>\n        <span class="token literal-property property">baseApi</span><span class="token operator">:</span><span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>\n        <span class="token literal-property property">mockApi</span><span class="token operator">:</span><span class="token string">&#39;&#39;</span>\n    <span class="token punctuation">}</span>\n<span class="token punctuation">}</span> \n<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>\n    env<span class="token punctuation">,</span>\n    <span class="token literal-property property">mock</span><span class="token operator">:</span><span class="token boolean">true</span><span class="token punctuation">,</span>\n    <span class="token comment">//baseApi:&#39;www.baudu.com/api&#39; 变为动态的了baseApi了调用上面的</span>\n    <span class="token operator">...</span>EnvConfig<span class="token punctuation">[</span>env<span class="token punctuation">]</span>\n<span class="token punctuation">}</span>\n</code></pre></div><h3 id="_2-mock数据" tabindex="-1"><a class="header-anchor" href="#_2-mock数据" aria-hidden="true">#</a> [2]mock数据</h3><p>在实际开发过程中环境变量通常是结合mock接口使用</p><p><img src="环境变量.assets/202204141927916.png" alt="image-20211128174912750"></p><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token comment">//环境配置封装</span>\n<span class="token keyword">const</span>  env <span class="token operator">=</span> <span class="token keyword">import</span><span class="token punctuation">.</span>meta<span class="token punctuation">.</span>env<span class="token punctuation">.</span><span class="token constant">MODE</span> <span class="token operator">||</span> <span class="token string">&#39;prod&#39;</span><span class="token punctuation">;</span>\n<span class="token keyword">const</span> EnvConfig <span class="token operator">=</span> <span class="token punctuation">{</span>\n    <span class="token comment">//开发环境</span>\n    <span class="token literal-property property">dev</span><span class="token operator">:</span><span class="token punctuation">{</span>\n        <span class="token literal-property property">baseApi</span><span class="token operator">:</span><span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>\n        <span class="token literal-property property">mockApi</span><span class="token operator">:</span><span class="token string">&#39;https://www.fastmock.site/mock/4c22c0ad9395bacbad44194547bc0155/api&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token comment">//测试环境</span>\n    <span class="token literal-property property">test</span><span class="token operator">:</span><span class="token punctuation">{</span>\n        <span class="token literal-property property">baseApi</span><span class="token operator">:</span><span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>\n        <span class="token literal-property property">mockApi</span><span class="token operator">:</span><span class="token string">&#39;https://www.fastmock.site/mock/4c22c0ad9395bacbad44194547bc0155/api&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token comment">//生产环境</span>\n    <span class="token literal-property property">prod</span><span class="token operator">:</span><span class="token punctuation">{</span>\n        <span class="token literal-property property">baseApi</span><span class="token operator">:</span><span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span>\n        <span class="token literal-property property">mockApi</span><span class="token operator">:</span><span class="token string">&#39;&#39;</span>\n    <span class="token punctuation">}</span>\n<span class="token punctuation">}</span> \n<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>\n    env<span class="token punctuation">,</span>\n    <span class="token literal-property property">mock</span><span class="token operator">:</span><span class="token boolean">true</span><span class="token punctuation">,</span>\n    <span class="token comment">//baseApi:&#39;www.baudu.com/api&#39; 变为动态的了baseApi了调用上面的</span>\n    <span class="token operator">...</span>EnvConfig<span class="token punctuation">[</span>env<span class="token punctuation">]</span>\n<span class="token punctuation">}</span>\n</code></pre></div><p><img src="环境变量.assets/202204141927071.png" alt="image-20211128174948584"></p><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token comment">//main.js</span>\n<span class="token keyword">import</span> <span class="token punctuation">{</span> createApp <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n<span class="token keyword">import</span> App <span class="token keyword">from</span> <span class="token string">&#39;./App.vue&#39;</span>\n<span class="token keyword">import</span> router <span class="token keyword">from</span> <span class="token string">&#39;./router&#39;</span>\n<span class="token keyword">import</span> ElementPlus <span class="token keyword">from</span> <span class="token string">&#39;element-plus&#39;</span>\n<span class="token keyword">import</span> <span class="token string">&#39;element-plus/dist/index.css&#39;</span>\n<span class="token keyword">import</span> axios <span class="token keyword">from</span> <span class="token string">&#39;axios&#39;</span> \n<span class="token keyword">import</span> config <span class="token keyword">from</span> <span class="token string">&#39;./config&#39;</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;环境变量=&gt;&quot;</span><span class="token punctuation">,</span> <span class="token keyword">import</span><span class="token punctuation">.</span>meta<span class="token punctuation">.</span>env<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token keyword">const</span> app<span class="token operator">=</span> <span class="token function">createApp</span><span class="token punctuation">(</span>App<span class="token punctuation">)</span>\naxios<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>config<span class="token punctuation">.</span>mockApi <span class="token operator">+</span> <span class="token string">&#39;/login&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">res</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>\n    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>res<span class="token punctuation">)</span> <span class="token comment">//测试，查看mock的数据</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n\napp<span class="token punctuation">.</span><span class="token function">use</span><span class="token punctuation">(</span>router<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">use</span><span class="token punctuation">(</span>ElementPlus<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">mount</span><span class="token punctuation">(</span><span class="token string">&#39;#app&#39;</span><span class="token punctuation">)</span>\n</code></pre></div>',38),e={},t=(0,a(3744).Z)(e,[["render",function(n,s){return p}]])},3744:(n,s)=>{s.Z=(n,s)=>{const a=n.__vccOpts||n;for(const[n,p]of s)a[n]=p;return a}}}]);